The function should process a list of musical notes and check if they all fall within the specified vocal range. Each note is represented as a string like "C4" or "G5", and the range is given as two strings, such as "A3" and "F5". The function will need to parse these strings to extract the note name and the octave, then compare the note's pitch to the range's lower and upper bounds.

```python
def is_note_in_range(notes, lower_bound, upper_bound):
    def parse_note(note):
        # Split the note into name and octave
        parts = note.split()
        if len(parts) == 1:
            return (parts[0], 4)  # Default octave if not provided
        else:
            name, octave = parts[0], int(parts[1])
            return (name, octave)

    def is_note_in_range(note, lower, upper):
        name, octave = parse_note(note)
        # Map note names to their corresponding MIDI numbers
        note_to_midi = {
            "C": 0, "C#": 1, "D": 2, "D#": 3, "E": 4, "F": 5, "F#": 6, "G": 7, "G#": 8, "A": 9, "A#": 10, "B": 11
        }
        midi = note_to_midi[name] + octave * 12
        return lower <= midi <= upper

    for note in notes:
        if not is_note_in_range(note, lower_bound, upper_bound):
            return False
    return True
